import json

import yaml

from prompty.model import ThreadMarker


def test_load_json_threadmarker():
    json_data = r"""
    {
      "name": "thread",
      "kind": "thread"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = ThreadMarker.load(data)
    assert instance is not None
    assert instance.name == "thread"
    assert instance.kind == "thread"


def test_load_yaml_threadmarker():
    yaml_data = r"""
    name: thread
    kind: thread

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
    instance = ThreadMarker.load(data)
    assert instance is not None
    assert instance.name == "thread"
    assert instance.kind == "thread"


def test_roundtrip_json_threadmarker():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "name": "thread",
      "kind": "thread"
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = ThreadMarker.load(original_data)
    saved_data = instance.save()
    reloaded = ThreadMarker.load(saved_data)
    assert reloaded is not None
    assert reloaded.name == "thread"
    assert reloaded.kind == "thread"


